export const ADDABLE_NODES = NODE_CATALOG.filter(node => node.addable);
export const DOCUMENTED_NODES = NODE_CATALOG.filter(node => !node.legacy);

export function getNodeMeta(type) {
  return NODE_CATALOG.find(node => node.type === type) || {
    type, icon: '⬜', label: type, desc: 'Неизвестный тип блока',
    purpose: 'Для этого блока пока нет описания.', when: '', nuances: [], example: '',
  };
}
